// ENEMY 1: ember slime — fire charger, reuse slime base
defineAnim('g_emberslime', 16, 14, 4, (p, f) => {
  const ph = f / 4;
  const yb = [0, 1, 2, 1][f % 4];
  // contact shadow + pulsing fire aura behind the body
  p.softShadow(8, 12, 5.5, 1.6, 0.34);
  p.aura(8, 9 + yb * 0.5, 5.5, P.ember, ph, 2);
  // molten body using ember tones; bright core glow inside
  drawSlime(p, f, P.ember, P.redD, P.emberL, P.white);
  p.glow(8, 9 + yb * 0.5, 3, P.emberL, 0.45, 3);   // inner lava core
  // glowing eyes with white catch-lights
  p.glow(6, 4 + yb, 1.6, P.emberL, 0.6, 2); p.glow(10, 4 + yb, 1.6, P.emberL, 0.6, 2);
  p.px(7, 4 + yb, P.emberL); p.px(9, 4 + yb, P.emberL);
  p.px(7, 3 + yb, P.white); p.px(9, 3 + yb, P.white);
  // little flame crest licking off the top
  p.line(8, 1 + yb, 7, 4 + yb, P.emberL); p.px(8, 0 + yb, P.white);
  // drips of molten light at the base
  p.ellipse(8, 9 + yb * 0.5, 2, 1.3, P.redL);
  p.px(4, 11, P.ember); p.px(12, 11, P.ember);
  p.rimLight(P.rim, 0.5);
  p.outline(P.ink);
  p.star4(13, 3, 2, P.emberL, P.white);            // ambient kira spark
}, { anchor: [8, 13], fps: 6 });

// ENEMY 2: frost wisp — ice shooter, reuse wisp base
defineAnim('g_frostwisp', 16, 16, 3, (p, f) => {
  const ph = f / 3;
  const yb = [0, -1, 0][f % 3];
  // cold halo + faint snow drift
  p.glow(8, 6 + yb, 6, P.ice, 0.32, 4);
  p.aura(8, 6 + yb, 6, P.rimCool, ph, 2);
  drawWisp(p, f, P.ice, P.iceD, P.white);
  // frosty crystalline core
  p.glow(8, 7 + yb, 2.4, P.hiSky, 0.55, 3);
  // big expressive icy eyes
  p.glow(5, 5 + yb, 1.4, P.iceD, 0.6, 2); p.glow(11, 5 + yb, 1.4, P.iceD, 0.6, 2);
  p.px(5, 5 + yb, P.iceD); p.px(11, 5 + yb, P.iceD);
  p.px(5, 4 + yb, P.white); p.px(11, 4 + yb, P.white);
  // ice crown spike + cheek glints
  p.line(8, 0 + yb, 8, 2 + yb, P.ice); p.px(8, 1 + yb, P.white);
  p.px(7, 6 + yb, P.blueL); p.px(9, 6 + yb, P.blueL);
  // drifting snow specks (deterministic)
  p.speckle(2, 2, 12, 10, withAlpha(P.white, 0.9), 4, f + 1);
  p.rimLight(P.rimCool, 0.5);
  p.outline(P.ink);
  p.star4(3, 4, 2, P.rimCool, P.white);
  p.sparkle(13, 9, P.ice, 1);
}, { anchor: [8, 12], fps: 5 });

// ENEMY 3: storm wisp — thunder shooter, reuse wisp base
defineAnim('g_stormwisp', 16, 16, 3, (p, f) => {
  const ph = f / 3;
  const yb = [0, -1, 0][f % 3];
  // electric neon halo + crackle aura
  p.glow(8, 6 + yb, 6, P.neon, 0.32, 4);
  p.aura(8, 6 + yb, 6, P.neonL, ph, 2);
  // storm-grey body with charged neon core eye
  drawWisp(p, f, P.gray2, P.gray1, P.neonL);
  p.glow(8, 7 + yb, 2.4, P.neon, 0.55, 3);
  // arc-light eyes
  p.glow(5, 5 + yb, 1.4, P.neon, 0.6, 2); p.glow(11, 5 + yb, 1.4, P.neon, 0.6, 2);
  p.px(5, 5 + yb, P.neonL); p.px(11, 5 + yb, P.neonL);
  p.px(5, 4 + yb, P.white); p.px(11, 4 + yb, P.white);
  // forked lightning crackling out of the body (cycles with the frame)
  const bx = [4, 11, 12][f % 3];
  p.line(bx, 7 + yb, bx - 1, 10 + yb, P.neonL);
  p.line(bx - 1, 10 + yb, bx + 1, 11 + yb, P.white);
  p.line(8, 4 + yb, 7, 8 + yb, P.neonL); p.line(7, 8 + yb, 9, 9 + yb, P.white);
  p.rimLight(P.neonL, 0.5);
  p.outline(P.ink);
  p.star4(12, 3, 2, P.neon, P.white);
  p.sparkle(3, 9, P.neonL, 1);
}, { anchor: [8, 12], fps: 6 });

