  // glowing acid veins / core in the chest
  p.glow(9, 10 + yb, 2.6, P.toxic, 0.4, 3);
  // venom eyes with catch-light
  p.glow(7, 6 + yb, 1.4, P.poison, 0.6, 2); p.glow(11, 6 + yb, 1.4, P.poison, 0.6, 2);
  p.px(7, 6 + yb, P.toxic); p.px(10, 6 + yb, P.toxic);
