// ENEMY 6: inferno brute — tier4 fire charger, reuse brute base (scaled via def.scale)
defineAnim('g_infernobrute', 18, 18, 2, (p, f) => {
  const ph = f / 2;
  const yb = f % 2 ? -1 : 0;
  // dramatic boss-tier shadow + double fire aura (volcanic)
  p.softShadow(9, 16, 7.5, 2.2, 0.4, P.blood);
  p.aura(9, 10 + yb, 8, P.ember, ph, 3);
  p.aura(9, 10 + yb, 6, P.redL, (ph + 0.5) % 1, 2);
  drawBrute(p, f, P.ember, P.redD, P.white);
  // searing molten core blazing through the chest
  p.glow(9, 10 + yb, 3.4, P.emberL, 0.55, 4);
  p.glow(9, 10 + yb, 1.6, P.white, 0.6, 2);
  // lava cracks crawling across the stone
  p.line(6, 9 + yb, 8, 13 + yb, P.emberL); p.line(11, 8 + yb, 12, 12 + yb, P.emberL);
  p.line(4, 11 + yb, 5, 14 + yb, P.ember);
  // blazing horns of flame
  p.line(6, 2 + yb, 5, -1 + yb, P.ember); p.line(11, 2 + yb, 12, -1 + yb, P.ember);
  p.px(6, 2 + yb, P.emberL); p.px(11, 2 + yb, P.emberL);
  p.px(8, 1 + yb, P.white); p.px(9, 1 + yb, P.white);
  // burning fists
  p.glow(2, 12 + yb, 2, P.emberL, 0.5, 2); p.glow(16, 12 + yb, 2, P.emberL, 0.5, 2);
  p.ellipse(2, 12 + yb, 1.2, 1.2, P.emberL); p.ellipse(16, 12 + yb, 1.2, 1.2, P.emberL);
  // furious glowing eyes
  p.px(7, 6 + yb, P.white); p.px(11, 6 + yb, P.white);
  p.speckle(3, 3, 12, 8, withAlpha(P.emberL, 0.8), 5, f + 3); // floating embers
  p.rimLight(P.rim, 0.6);
  p.outline(P.ink);
  p.star4(15, 3, 2, P.emberL, P.white); p.star4(3, 14, 2, P.redL, P.white);
}, { anchor: [9, 17], fps: 3 });

